\displaystyle{\begin{aligned}
  \frac{{\frac{1}{x-4}+\frac{5}{x-4}}}{{2-\frac{1}{x+4}}} \amp = \frac{({\frac{1}{x-4}+\frac{5}{x-4}})\cdot{\left(x+4\right)\mathopen{}\left(x-4\right)}}{({2-\frac{1}{x+4}})\cdot{\left(x+4\right)\mathopen{}\left(x-4\right)}} \\
    \amp = \frac{{\frac{1}{x-4}\mathopen{}\left(x+4\right)\mathopen{}\left(x-4\right)+\frac{5}{x-4}\mathopen{}\left(x+4\right)\mathopen{}\left(x-4\right)}}{{2\mathopen{}\left(x+4\right)\mathopen{}\left(x-4\right)-\frac{1}{x+4}\mathopen{}\left(x+4\right)\mathopen{}\left(x-4\right)}} \\
    \amp = \frac{{x+4+5\mathopen{}\left(x+4\right)}}{{2\mathopen{}\left(x^{2}-16\right)-\left(x-4\right)}}, x \ne 4 \text{ and }  x \ne -4 \\
    \amp = \frac{{x+4+5x+20}}{{2x^{2}-32-x+4}}, x \ne 4 \text{ and }  x \ne -4 \\
    \amp = \frac{{6x+24}}{{2x^{2}-x-28}}, x \ne 4 \text{ and }  x \ne -4 \\
    \amp = {\frac{6\mathopen{}\left(x+4\right)}{\left(2x+7\right)\mathopen{}\left(x-4\right)}, x\ne -4}
\end{aligned}
    }
